sql:
SELECT f.func_name, f.func_complexity, pm.execution_time, pm.performance_gflops
FROM functions f
INNER JOIN performance_metrics pm ON f.func_id = pm.func_id;

SELECT func_name, func_language, func_complexity, func_author
FROM functions
WHERE func_complexity IN ('medium', 'high');

external_knowledge:
'capability to modify' refers to having 'edit' access type;
'research role' refers to the role with 'role_name' 'researcher';
individuals means user records in the 'users' table;

sql:
SELECT task_name
FROM optimization_tasks
WHERE user_id = 1 AND status = 'in progress';

SELECT func_name, func_complexity, func_author 
FROM functions 
ORDER BY func_complexity DESC;

SELECT users.user_name, job_runs.job_name
FROM users
INNER JOIN job_runs ON users.user_id = job_runs.job_owner_id;

SELECT t.task_id, t.task_name, m.execution_time
FROM optimization_tasks AS t 
JOIN task_metrics AS m ON t.task_id = m.task_id
WHERE m.execution_time = (
    SELECT MAX(execution_time) FROM task_metrics
);

SELECT job_id, execution_time
FROM job_metrics
WHERE execution_time > 0.1;

external_knowledge:
- 'Pythonic functions' refers to functions written in Python;
- 'Matured to a medium level of complexity' refers to functions with complexity classified as 'medium';
- 'Blazing faster than the slow-paced 50 gigaflops threshold' means functions that have an average performance greater than 50 GFLOPS.

sql:
SELECT t1.task_name, t2.file_path
FROM optimization_tasks AS t1
INNER JOIN task_files AS t2 ON t1.task_id = t2.task_id;

SELECT func_name, func_description
FROM functions
WHERE func_complexity = 'high';

SELECT AVG(num_comments) as avg_comments_per_user
FROM (
  SELECT user_id, COUNT(*) as num_comments
  FROM task_comments
  GROUP BY user_id
);

external_knowledge:
- "devouring more than half of the CPU's energy" refers to functions with a CPU utilization greater than 50.0%.;
- "identities" refers to the names of the functions.;
- "the tales they tell (descriptions)" refers to the descriptions of the functions.;
- "their generations (versions)" refers to the versions of the functions.

